WITH all_objects AS (SELECT c.oid AS object_id, CASE c.relkind WHEN 'r' THEN 'TABLE' WHEN 'm' THEN 'MATERIALIZED_VIEW' WHEN 'f' THEN 'FOREIGN_TABLE' WHEN 'p' THEN 'PARTITIONED_TABLE' ELSE 'UNCATEGORIZED' END AS object_type, ns.nspname AS object_schema, c.relname AS object_name, r.rolname AS owner_name, c.reltuples AS estimated_row_count, c.relpages AS estimated_page_count, CAST(c.reloptions AS TEXT) AS storage_options, CAST(tc.reloptions AS TEXT) AS toast_options FROM pg_class AS c JOIN pg_catalog.pg_namespace AS ns ON (c.relnamespace = ns.oid) JOIN pg_catalog.pg_roles AS r ON (c.relowner = r.oid) LEFT JOIN pg_catalog.pg_class AS tc ON (c.reltoastrelid = tc.oid) WHERE ns.nspname <> ALL(ARRAY['pg_catalog', 'information_schema']) AND NOT ns.nspname ~ '^pg_toast' AND c.relkind = ANY(ARRAY['r', 'p', 'm', 'f'])), stat_user_tables AS (SELECT t.relid AS object_id, PG_TOTAL_RELATION_SIZE(t.relid) AS total_object_size_bytes, PG_RELATION_SIZE(t.relid) AS object_size_bytes, PG_INDEXES_SIZE(t.relid) AS index_size_bytes, t.seq_scan AS sequence_scan, t.seq_tup_read AS sequence_tuples_read, t.idx_scan AS index_scan, t.idx_tup_fetch AS index_tuples_fetched, t.n_tup_ins AS tuples_inserted, t.n_tup_upd AS tuples_updated, t.n_tup_del AS tuples_deleted, t.n_tup_hot_upd AS tuples_hot_updated, t.n_live_tup AS live_tuples, t.n_dead_tup AS dead_tuples, t.n_mod_since_analyze AS modifications_since_last_analyzed, t.n_ins_since_vacuum AS inserts_since_last_vacuumed, t.last_analyze AS last_analyzed, t.last_autoanalyze AS last_autoanalyzed, t.last_autovacuum AS last_autovacuumed, t.last_vacuum AS last_vacuumed, t.vacuum_count AS vacuum_count, t.analyze_count AS analyze_count, t.autoanalyze_count AS autoanalyze_count, t.autovacuum_count AS autovacuum_count FROM pg_stat_user_tables AS t), statio_user_tables AS (SELECT s.relid AS object_id, s.heap_blks_hit AS heap_blocks_hit, s.heap_blks_read AS heap_blocks_read, s.idx_blks_hit AS index_blocks_hit, s.idx_blks_read AS index_blocks_read, s.toast_blks_hit AS toast_blocks_hit, s.toast_blks_read AS toast_blocks_read, s.tidx_blks_hit AS toast_index_hit, s.tidx_blks_read AS toast_index_read FROM pg_statio_user_tables AS s), foreign_tables AS (SELECT ft.ftrelid AS object_id, s.srvname AS foreign_server_name, w.fdwname AS foreign_data_wrapper_name FROM pg_catalog.pg_foreign_table AS ft INNER JOIN pg_catalog.pg_class AS c ON c.oid = ft.ftrelid INNER JOIN pg_catalog.pg_foreign_server AS s ON s.oid = ft.ftserver INNER JOIN pg_catalog.pg_foreign_data_wrapper AS w ON s.srvfdw = w.oid), src AS (SELECT a.object_id, a.object_type AS table_type, a.object_name AS table_name, a.object_schema AS table_schema, a.owner_name, a.estimated_row_count, a.estimated_page_count, a.storage_options, a.toast_options, t.total_object_size_bytes, t.object_size_bytes, t.index_size_bytes, t.sequence_scan, t.sequence_tuples_read, t.index_scan, t.index_tuples_fetched, t.tuples_inserted, t.tuples_updated, t.tuples_deleted, t.tuples_hot_updated, t.live_tuples, t.dead_tuples, t.modifications_since_last_analyzed, t.inserts_since_last_vacuumed, t.last_analyzed, t.last_autoanalyzed, t.last_autovacuumed, t.last_vacuumed, t.vacuum_count, t.analyze_count, t.autoanalyze_count, t.autovacuum_count, f.foreign_server_name, f.foreign_data_wrapper_name, s.heap_blocks_hit, s.heap_blocks_read, s.index_blocks_hit, s.index_blocks_read, s.toast_blocks_hit, s.toast_blocks_read, s.toast_index_hit, s.toast_index_read FROM all_objects AS a LEFT JOIN stat_user_tables AS t ON (a.object_id = t.object_id) LEFT JOIN statio_user_tables AS s ON (a.object_id = s.object_id) LEFT JOIN foreign_tables AS f ON (a.object_id = f.object_id)) SELECT CHR(34) || :PKEY || CHR(34) AS pkey, CHR(34) || :DMA_SOURCE_ID || CHR(34) AS dma_source_id, CHR(34) || :DMA_MANUAL_ID || CHR(34) AS dma_manual_id, CHR(34) || src.object_id || CHR(34) AS object_id, CHR(34) || REPLACE(src.table_schema, CHR(34), CHR(30)) || CHR(34) AS table_schema, CHR(34) || src.table_type || CHR(34) AS table_type, CHR(34) || REPLACE(src.table_name, CHR(34), CHR(39)) || CHR(34) AS table_name, src.owner_name, src.estimated_row_count, src.estimated_page_count, src.storage_options, src.toast_options, src.total_object_size_bytes AS total_object_size_bytes, src.object_size_bytes AS object_size_bytes, src.index_size_bytes AS index_size_bytes, src.sequence_scan AS sequence_scan, src.sequence_tuples_read, src.index_scan AS index_scan, src.index_tuples_fetched, src.tuples_inserted, src.tuples_updated, src.tuples_deleted, src.tuples_hot_updated, CHR(34) || src.live_tuples || CHR(34) AS live_tuples, CHR(34) || src.dead_tuples || CHR(34) AS dead_tuples, src.modifications_since_last_analyzed AS modifications_since_last_analyzed, CHR(34) || src.last_analyzed || CHR(34) AS last_analyzed, CHR(34) || src.last_autoanalyzed || CHR(34) AS last_autoanalyzed, CHR(34) || src.last_autovacuumed || CHR(34) AS last_autovacuumed, CHR(34) || src.last_vacuumed || CHR(34) AS last_vacuumed, src.vacuum_count AS vacuum_count, src.analyze_count AS analyze_count, src.autoanalyze_count AS autoanalyze_count, src.autovacuum_count AS autovacuum_count, CHR(34) || src.foreign_server_name || CHR(34) AS foreign_server_name, CHR(34) || src.foreign_data_wrapper_name || CHR(34) AS foreign_data_wrapper_name, COALESCE(src.heap_blocks_hit, 0) AS heap_blocks_hit, COALESCE(src.heap_blocks_read, 0) AS heap_blocks_read, COALESCE(src.index_blocks_hit, 0) AS index_blocks_hit, COALESCE(src.index_blocks_read, 0) AS index_blocks_read, COALESCE(src.toast_blocks_hit, 0) AS toast_blocks_hit, COALESCE(src.toast_blocks_read, 0) AS toast_blocks_read, COALESCE(src.toast_index_hit, 0) AS toast_index_hit, COALESCE(src.toast_index_read, 0) AS toast_index_read, CHR(34) || CURRENT_DATABASE() || CHR(34) AS database_name FROM src